input.command:
Write-Output "=== Idle baseline ==="; $idle=(Test-Connection 1.1.1.1 -Count 5).ResponseTime; $imin=($idle|Measure -Min).Minimum; Write-Output "Idle avg:$([math]::Round(($idle|Measure -Average).Average,1))ms min:${imin}ms max:$(($idle|Measure -Max).Maximum)ms"
Write-Output "=== Loading line (download to memory) + concurrent ping ==="
$job = Start-Job { try { (New-Object System.Net.WebClient).DownloadData('https://speed.cloudflare.com/__down?bytes=80000000') | Out-Null } catch {} }
Start-Sleep -Milliseconds 700
$loaded=@(); 1..20 | ForEach-Object { $p=Test-Connection 1.1.1.1 -Count 1 -ErrorAction SilentlyContinue; if($p){$loaded+=$p.ResponseTime}; Start-Sleep -Milliseconds 150 }
Stop-Job $job -ErrorAction SilentlyContinue; Remove-Job $job -Force -ErrorAction SilentlyContinue
$la=[math]::Round(($loaded|Measure -Average).Average,1); $lmax=($loaded|Measure -Max).Maximum; $lmin=($loaded|Measure -Min).Minimum
Write-Output "Loaded avg:${la}ms min:${lmin}ms max:${lmax}ms (samples:$($loaded.Count))"
$bloat=$lmax-$imin; Write-Output "=== Bufferbloat (loaded max - idle min): +${bloat}ms ==="
if($bloat -gt 80){Write-Output 'VERDICT: SEVERE bufferbloat -> almost certainly the jaggy-ball cause'}elseif($bloat -gt 40){Write-Output 'VERDICT: MODERATE bufferbloat -> contributes to ball stutter under load'}else{Write-Output 'VERDICT: bufferbloat LOW -> investigate game-server path / intermittent loss instead'}

Write-Output "=== Idle baseline ==="; $idle=(Test-Connection 1.1.1.1 -Count 5).ResponseTime; $imin=($idle|Measure -Min).Minimum; Write-Output "Idle min:${imin}ms avg:$([math]::Round(($idle|Measure -Average).Average,1))ms"
Write-Output "=== Loading UPLOAD + concurrent ping ==="
$job = Start-Job { try { $data=New-Object byte[] (60MB); $wc=New-Object System.Net.WebClient; 1..3 | ForEach-Object { $wc.UploadData('https://speed.cloudflare.com/__up','POST',$data) | Out-Null } } catch {} }
Start-Sleep -Milliseconds 800
$loaded=@(); 1..20 | ForEach-Object { $p=Test-Connection 1.1.1.1 -Count 1 -ErrorAction SilentlyContinue; if($p){$loaded+=$p.ResponseTime}; Start-Sleep -Milliseconds 150 }
Stop-Job $job -ErrorAction SilentlyContinue; Remove-Job $job -Force -ErrorAction SilentlyContinue
$la=[math]::Round(($loaded|Measure -Average).Average,1); $lmax=($loaded|Measure -Max).Maximum
Write-Output "Loaded(upload) avg:${la}ms min:$(($loaded|Measure -Min).Minimum)ms max:${lmax}ms samples:$($loaded.Count)"
$bloat=$lmax-$imin; Write-Output "=== Upload bufferbloat: +${bloat}ms ==="
if($bloat -gt 80){Write-Output 'VERDICT: SEVERE upload bufferbloat -> jaggy ball while streaming/uploading is THIS'}elseif($bloat -gt 40){Write-Output 'VERDICT: MODERATE upload bufferbloat'}else{Write-Output 'VERDICT: upload bufferbloat LOW too'}

Write-Output "=== Is streaming/capture software running? ==="; Get-Process obs64,obs32,obs,XSplit,streamlabs,nvcontainer,OneComme,VOICEVOX,'棒読みちゃん',Discord -ErrorAction SilentlyContinue | Select-Object Name, @{N='CPU(s)';E={[math]::Round($_.CPU,0)}}, @{N='RAM(MB)';E={[math]::Round($_.WorkingSet64/1MB,0)}} | Format-Table -AutoSize
Write-Output "=== Display refresh rate & resolution ==="; Add-Type -AssemblyName System.Windows.Forms; Get-CimInstance -Namespace root\wmi -ClassName WmiMonitorBasicDisplayParams -ErrorAction SilentlyContinue | Out-Null; $vc=Get-CimInstance Win32_VideoController; $vc | Select-Object Name, CurrentHorizontalResolution, CurrentVerticalResolution, CurrentRefreshRate, MaxRefreshRate | Format-Table -AutoSize
Write-Output "=== GPU engine utilization (3D + encode) ==="; $g=(Get-Counter '\GPU Engine(*)\Utilization Percentage' -ErrorAction SilentlyContinue).CounterSamples; ($g | Where-Object {$_.InstanceName -like '*engtype_3D*' -and $_.CookedValue -gt 0} | Measure-Object CookedValue -Sum).Sum | ForEach-Object {"3D total: $([math]::Round($_,0))%"}; ($g | Where-Object {$_.InstanceName -like '*engtype_VideoEncode*' -and $_.CookedValue -gt 0} | Measure-Object CookedValue -Sum).Sum | ForEach-Object {"VideoEncode total: $([math]::Round($_,0))%"}

$g=(Get-Counter '\GPU Engine(*)\Utilization Percentage' -ErrorAction SilentlyContinue).CounterSamples | Where-Object {$_.CookedValue -gt 1}
function PidName($inst){ if($inst -match 'pid_(\d+)'){ $procid=$matches[1]; $n=(Get-Process -Id $procid -ErrorAction SilentlyContinue).ProcessName; if($n){"$n (PID $procid)"}else{"PID $procid"} } else {'?'} }
Write-Output "=== Who is using VideoEncode (NVENC) ==="
$g | Where-Object {$_.InstanceName -like '*VideoEncode*'} | ForEach-Object { "{0,5}%  {1}" -f [math]::Round($_.CookedValue,0), (PidName $_.InstanceName) }
Write-Output "=== Top 3D GPU consumers by process ==="
$g | Where-Object {$_.InstanceName -like '*3D*'} | Sort-Object CookedValue -Descending | Select-Object -First 6 | ForEach-Object { "{0,5}%  {1}" -f [math]::Round($_.CookedValue,0), (PidName $_.InstanceName) }
Write-Output "=== RocketLeague process state ==="
$rl=Get-Process -Name RocketLeague -ErrorAction SilentlyContinue; if($rl){ "RL PID $($rl.Id)  CPU:$([math]::Round($rl.CPU,0))s  RAM:$([math]::Round($rl.WorkingSet64/1MB,0))MB  Priority:$($rl.PriorityClass)  Threads:$($rl.Threads.Count)" }

Write-Output "=== NIC status ==="; Get-NetAdapter -InterfaceDescription 'Realtek PCIe 2.5GbE Family Controller' | Select-Object Name,Status,LinkSpeed | Format-Table -AutoSize
Write-Output "=== Reconfirm Interrupt Moderation ==="; (Get-NetAdapterAdvancedProperty -InterfaceDescription 'Realtek PCIe 2.5GbE Family Controller' -DisplayName 'Interrupt Moderation').DisplayValue
Write-Output "=== Connectivity to your game server restored? ==="; $rt=(Test-Connection 35.78.159.96 -Count 8 -ErrorAction SilentlyContinue).ResponseTime; if($rt){ "Recv:$($rt.Count)/8  Avg:$([math]::Round(($rt|Measure -Average).Average,1))ms  Min:$(($rt|Measure -Min).Minimum) Max:$(($rt|Measure -Max).Maximum)ms" } else { "No reply (check game still connected)" }

Write-Output "=== Baseline latency log $(Get-Date -Format 'HH:mm:ss') ==="
foreach($t in @('1.1.1.1','8.8.8.8','27.86.18.173')){
  $rt=@(); for($i=0;$i -lt 40;$i++){ $p=Test-Connection $t -Count 1 -ErrorAction SilentlyContinue; if($p){$rt+=$p.ResponseTime}; Start-Sleep -Milliseconds 80 }
  if($rt.Count){ "{0,-16} recv:{1,2}/40 loss:{2,4}%  min:{3} avg:{4} max:{5}ms jitter:{6}ms" -f $t,$rt.Count,[math]::Round((40-$rt.Count)/40*100,1),($rt|Measure -Min).Minimum,[math]::Round(($rt|Measure -Average).Average,1),($rt|Measure -Max).Maximum,(($rt|Measure -Max).Maximum-($rt|Measure -Min).Minimum) }
  else { "{0,-16} no reply" -f $t }
}
Write-Output "(27.86.18.173 = spcBBAR002 KDDI near-node; +16ms jump happens beyond it toward Tokyo peering)"
